package dev.harrison.rendacomcarro.finance.web;
import dev.harrison.rendacomcarro.finance.application.FinancialObligationService;import dev.harrison.rendacomcarro.finance.domain.*;import dev.harrison.rendacomcarro.vehicle.application.VehicleService;import jakarta.validation.Valid;import java.util.UUID;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.validation.BindingResult;import org.springframework.web.bind.annotation.*;import org.springframework.web.servlet.mvc.support.RedirectAttributes;
@Controller@RequestMapping("/obligations")public class FinancialObligationController {private final FinancialObligationService service;private final VehicleService vehicles;public FinancialObligationController(FinancialObligationService s,VehicleService v){service=s;vehicles=v;}@ModelAttribute("types")ObligationType[]types(){return ObligationType.values();}@ModelAttribute("modes")ObligationMode[]modes(){return ObligationMode.values();}@GetMapping public String list(Model m){m.addAttribute("obligations",service.list());return"obligations/list";}@GetMapping("/new")public String form(Model m){m.addAttribute("obligationForm",new ObligationForm());m.addAttribute("vehicles",vehicles.listAll());return"obligations/form";}@PostMapping public String create(@Valid@ModelAttribute ObligationForm f,BindingResult r,Model m,RedirectAttributes ra){if(r.hasErrors()){m.addAttribute("vehicles",vehicles.listAll());return"obligations/form";}var o=service.create(new FinancialObligationService.CreateCommand(f.getVehicleId(),f.getType(),f.getMode(),f.getCreditor(),f.getPrincipal(),f.getAnnualRate(),f.getStartDate(),f.getFirstDueDate(),f.getTermMonths(),f.getPlannedInstallment(),f.getMonthlyTarget(),f.getNotes()));ra.addFlashAttribute("successMessage","Obrigação cadastrada.");return"redirect:/obligations/"+o.getId();}@GetMapping("/{id}")public String detail(@PathVariable UUID id,Model m){m.addAttribute("obligation",service.get(id));m.addAttribute("schedule",service.schedule(id));m.addAttribute("payments",service.paymentHistory(id));return"obligations/detail";}@GetMapping("/{id}/payments/new")public String paymentForm(@PathVariable UUID id,Model m){m.addAttribute("obligation",service.get(id));m.addAttribute("paymentForm",new PaymentForm());return"obligations/payment-form";}@PostMapping("/{id}/payments")public String pay(@PathVariable UUID id,@Valid@ModelAttribute PaymentForm f,BindingResult r,Model m,RedirectAttributes ra){if(r.hasErrors()){m.addAttribute("obligation",service.get(id));return"obligations/payment-form";}service.pay(id,f.getDate(),f.getPrincipal(),f.getInterest(),f.getExtra(),f.getExternalReference(),f.getNotes());ra.addFlashAttribute("successMessage","Pagamento registrado.");return"redirect:/obligations/"+id;}}
